@using sv_c528f717dfa04889af72b4a34d9e09ea.Services

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="section-icon">@section.Value.Icon</span>
                    @section.Value.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly Dictionary<string, (string Label, string Icon)> Sections = new()
    {
        ["Profile"] = ("Profile", "👤"),
        ["Notifications"] = ("Notifications", "🔔"),
        ["Security"] = ("Security", "🔒"),
        ["Appearance"] = ("Appearance", "🎨"),
    };
}

.settings-sidebar {
    padding: 1rem 0;
}

.sidebar-title {
    padding: 0 1rem 0.75rem;
    margin-bottom: 0.5rem;
    font-weight: 600;
    border-bottom: 1px solid #dee2e6;
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    border-radius: 0;
    cursor: pointer;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.section-icon {
    font-size: 1.1rem;
}

@using sv_c528f717dfa04889af72b4a34d9e09ea.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <h4>Profile</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="avatar-area mb-3">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
            <small class="text-muted d-block mt-1">@_avatarUrl</small>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>
        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>
        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="3" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _statusMessage = null;
    }
}

.profile-section {
    max-width: 600px;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
}

@using sv_c528f717dfa04889af72b4a34d9e09ea.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
    else
    {
        <h4>Notifications</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
