@using sv_c528f717dfa04889af72b4a34d9e09ea.Services

<div class="change-password-panel">
    <button class="btn btn-outline-secondary mb-2" @onclick="() => _expanded = !_expanded">
        @(_expanded ? "▾" : "▸") Change Password
    </button>

    @if (_expanded)
    {
        <div class="card card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-2">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-2">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_updating">
                @(_updating ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _message;
    private bool _isError;
    private bool _updating;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "All password fields are required.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New passwords do not match.";
            _isError = true;
            return;
        }

        _updating = true;
        try
        {
            await OnPasswordChanged.InvokeAsync();
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _updating = false;
        }
    }
}

.change-password-panel .card {
    max-width: 400px;
    margin-bottom: 1rem;
}

@using sv_c528f717dfa04889af72b4a34d9e09ea.Services

<div class="active-sessions-table">
    <h6>Active Sessions</h6>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <table class="table table-striped table-sm">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (session.Id == CurrentSessionId)
                            {
                                <span class="badge bg-success">Current</span>
                            }
                            else if (_confirmingId == session.Id)
                            {
                                <span class="me-2 text-danger">Revoke?</span>
                                <button class="btn btn-danger btn-sm me-1" @onclick="() => ConfirmRevoke(session.Id)">
                                    Yes
                                </button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke">
                                    No
                                </button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RequestRevoke(session.Id)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void RequestRevoke(string sessionId) => _confirmingId = sessionId;

    private void CancelRevoke() => _confirmingId = null;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var elapsed = DateTime.UtcNow - dt;
        if (elapsed.TotalMinutes < 1) return "Just now";
        if (elapsed.TotalMinutes < 60) return $"{(int)elapsed.TotalMinutes}m ago";
        if (elapsed.TotalHours < 24) return $"{(int)elapsed.TotalHours}h ago";
        return $"{(int)elapsed.TotalDays}d ago";
    }
}

