{"file_text": "@using sv_c528f717dfa04889af72b4a34d9e09ea.Services

<div class="active-sessions-table">
    <h6>Active Sessions</h6>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <table class="table table-striped table-sm">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (session.Id == CurrentSessionId)
                            {
                                <span class="badge bg-success">Current</span>
                            }
                            else if (_confirmingId == session.Id)
                            {
                                <span class="me-2 text-danger">Revoke?</span>
                                <button class="btn btn-danger btn-sm me-1" @onclick="() => ConfirmRevoke(session.Id)">
                                    Yes
                                </button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke">
                                    No
                                </button>
                            }
                            else
                            {
                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RequestRevoke(session.Id)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void RequestRevoke(string sessionId) => _confirmingId = sessionId;

    private void CancelRevoke() => _confirmingId = null;

    private async Task ConfirmRevoke(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime dt)
    {
        var elapsed = DateTime.UtcNow - dt;
        if (elapsed.TotalMinutes < 1) return "Just now";
        if (elapsed.TotalMinutes < 60) return $"{(int)elapsed.TotalMinutes}m ago";
        if (elapsed.TotalHours < 24) return $"{(int)elapsed.TotalHours}h ago";
        return $"{(int)elapsed.TotalDays}d ago";
    }
}
