@using sv_c528f717dfa04889af72b4a34d9e09ea.Services
@inject ISettingsService SettingsService

<div class="security-section">
    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <h4>Security</h4>

        <ChangePasswordPanel OnPasswordChanged="HandlePasswordChange" />

        <div class="mb-4">
            <h6>Two-Factor Authentication</h6>
            <div class="d-flex align-items-center gap-2">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor" checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="twoFactor">Enable 2FA</label>
                </div>
                <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(_twoFactorEnabled ? "Enabled" : "Disabled")
                </span>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <small class="text-muted d-block mt-2">
                    Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                </small>
            }
        </div>

        <ActiveSessionsTable Sessions="_sessions" CurrentSessionId="sess-1" OnRevoke="HandleRevokeSession" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task HandlePasswordChange()
    {
        await SettingsService.ChangePasswordAsync("", "");
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

