@using sv_c528f717dfa04889af72b4a34d9e09ea.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <h4>Appearance</h4>

        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="mb-4">
            <h6>Theme</h6>
            @foreach (var theme in _themes)
            {
                <div class="form-check">
                    <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                           value="@theme" checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <label class="form-check-label" for="theme-@theme">@theme</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <h6>Font Size</h6>
            @foreach (var size in _fontSizes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                           value="@size" checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <label class="form-check-label" for="fs-@size">@size</label>
                </div>
            }
        </div>

        <div class="mb-4">
            <label class="form-label"><strong>Language</strong></label>
            <select class="form-select" style="max-width: 250px;"
                    @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <div class="mb-4">
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>
        </div>

        <div class="mb-4">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <p class="preview-title">Sample Heading</p>
                <p>This is how your content will look with the selected settings.</p>
                <button class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-primary")">Sample Button</button>
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save")
        </button>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme switch
        {
            "Dark" => "preview-dark",
            _ => "preview-light"
        });
        classes.Add(_fontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _statusMessage = "Appearance settings saved!";
        _saving = false;
    }
}

